import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import java.security.Key;
import java.util.Base64;

public class AESEncryptionUtil {

    private static final String SECRET_KEY = "your_secret_key_here"; // replace with your secret key

    public static byte[] encrypt(byte[] data) throws Exception {
        Key aesKey = new SecretKeySpec(SECRET_KEY.getBytes(), "AES");
        Cipher cipher = Cipher.getInstance("AES");
        cipher.init(Cipher.ENCRYPT_MODE, aesKey);
        return cipher.doFinal(data);
    }

    public static byte[] decrypt(byte[] data) throws Exception {
        Key aesKey = new SecretKeySpec(SECRET_KEY.getBytes(), "AES");
        Cipher cipher = Cipher.getInstance("AES");
        cipher.init(Cipher.DECRYPT_MODE, aesKey);
        return cipher.doFinal(data);
    }

    // Function to convert a string to bytes
    private static byte[] strToBytes(String data) {
        return data.getBytes();
    }

    // Function to convert bytes to string
    private static String bytesToStr(byte[] data) {
        return new String(data);
    }

    public static byte[] encryptString(String data) throws Exception {
        return encrypt(strToBytes(data));
    }

    public static String decryptString(byte[] data) throws Exception {
        return bytesToStr(decrypt(data));
    }
}